import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

ReactDOM.createRoot(document.getElementById('root')!).render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React from 'react'
import Workbench from './components/Workbench'
import { ConfigProvider } from 'antd'
import zhCN from 'antd/locale/zh_CN'
import './App.css'

const App: React.FC = () => {
  return (
    <ConfigProvider
      locale={zhCN}
      theme={{
        token: {
          colorPrimary: '#1890ff',
        },
      }}
    >
      <Workbench />
    </ConfigProvider>
  )
}

export default App

/**
 * 向量语义检索面板
 * 提供相似章节搜索功能
 *
 * 降级方案：基于倒排索引的关键词搜索
 * 当 @xenova/transformers 不可用时自动启用
 */

import { useState, useEffect, useMemo, useRef } from 'react'
import {
  Input,
  Button,
  List,
  Card,
  Tag,
  Space,
  message,
  Alert,
  Spin,
  Modal,
  Select,
  Tooltip,
  Checkbox,
  Badge,
} from 'antd'
import {
  SearchOutlined,
  BuildOutlined,
  CheckCircleOutlined,
  WarningOutlined,
  ReloadOutlined,
  FilterOutlined,
} from '@ant-design/icons'

interface SearchResult {
  chapterPath: string
  chapterName: string
  score: number
  snippet: string
  matchedWords: string[]
}

interface ChapterEntry {
  path: string
  name: string
  content: string
}

interface InvertedIndex {
  vocabulary: Map<string, Set<string>> // word -> Set<chapterPath>
  totalDocs: number
  docLengths: Map<string, number>
}

interface VectorSearchPanelProps {
  projectRoot: string | null
  onJumpToChapter?: (chapterPath: string) => void
}

const VectorSearchPanel: React.FC<VectorSearchPanelProps> = ({
  projectRoot,
  onJumpToChapter,
}) => {
  const [query, setQuery] = useState('')
  const [results, setResults] = useState<SearchResult[]>([])
  const [loading, setLoading] = useState(false)
  const [indexLoading, setIndexLoading] = useState(false)
  const [chapters, setChapters] = useState<ChapterEntry[]>([])
  const [invertedIndex, setInvertedIndex] = useState<InvertedIndex | null>(null)
  const [queryMode, setQueryMode] = useState<'AND' | 'OR'>('AND')
  const [chapterRange, setChapterRange] = useState<{ start?: number; end?: number }>({})
  const [showFilters, setShowFilters] = useState(false)
  const [indexStats, setIndexStats] = useState<{ wordCount: number; chapterCount: number } | null>(null)
  const loadIdRef = useRef(0)

  // 加载所有章节内容并构建倒排索引
  const loadChaptersAndBuildIndex = async (loadId: number): Promise<{ chapters: ChapterEntry[]; index: InvertedIndex } | null> => {
    if (!projectRoot) return null
    if (loadIdRef.current !== loadId) return null  // 忽略过时调用

    setIndexLoading(true)
    const loadedChapters: ChapterEntry[] = []

    const readDir = async (dirPath: string) => {
      try {
        const entriesResult = await window.electronAPI.readdir(dirPath)
        if (!entriesResult.success) { console.warn('读取目录失败:', dirPath, entriesResult.error); return; }
        const entries = entriesResult.data || []
        for (const entry of entries) {
          const fullPath = `${dirPath}/${entry.name}`
          if (entry.isDirectory) {
            await readDir(fullPath)
          } else if (entry.isFile && entry.name.endsWith('.md') && !entry.name.startsWith('_')) {
            const contentResult = await window.electronAPI.readFile(fullPath)
            if (contentResult.success && contentResult.content) {
              loadedChapters.push({
                path: fullPath,
                name: entry.name.replace('.md', ''),
                content: contentResult.content,
              })
            }
          }
        }
      } catch (e) {
        console.warn('读取目录失败:', dirPath, e)
      }
    }

    const plotsDir = `${projectRoot}/plots`
    let dirExists = false
    try {
      const r = await window.electronAPI.exists(plotsDir)
      dirExists = !!(r && r.success && r.exists)
    } catch (e) {
      console.warn('exists 调用异常:', e)
    }
    if (dirExists) {
      await readDir(plotsDir)
    }

    if (loadedChapters.length === 0) {
      setIndexLoading(false)
      return null
    }

    if (loadIdRef.current !== loadId) return null  // 忽略过时调用
    setChapters(loadedChapters)

    // 构建倒排索引
    const vocab = new Map<string, Set<string>>()
    const docLengths = new Map<string, number>()

    // 中文分词简单实现（基于字典+规则）
    const tokenize = (text: string): string[] => {
      // 去除标点和空格，转小写
      const clean = text.replace(/[^\w\u4e00-\u9fa5]/g, ' ').toLowerCase()
      // 简单按空格和非汉字字符分割
      const words = clean.split(/[\s,。！？、：；""''【】『』]+/).filter(w => w.length >= 1)
      return words
    }

    for (const ch of loadedChapters) {
      const words = tokenize(ch.content)
      docLengths.set(ch.path, words.length)

      for (const word of words) {
        if (word.length < 1) continue
        if (!vocab.has(word)) {
          vocab.set(word, new Set())
        }
        vocab.get(word)!.add(ch.path)
      }
    }

    const index: InvertedIndex = {
      vocabulary: vocab,
      totalDocs: loadedChapters.length,
      docLengths,
    }

    if (loadIdRef.current !== loadId) return null  // 忽略过时调用
    setInvertedIndex(index)
    setIndexStats({
      wordCount: vocab.size,
      chapterCount: loadedChapters.length,
    })
    setIndexLoading(false)

    return { chapters: loadedChapters, index }
  }

  // 初始化时构建索引
  useEffect(() => {
    if (projectRoot) {
      loadIdRef.current += 1
      loadChaptersAndBuildIndex(loadIdRef.current)
    }
  }, [projectRoot])

  // 搜索
  const performSearch = async () => {
    if (!query.trim()) {
      message.warning('请输入搜索内容')
      return
    }
    if (!invertedIndex || chapters.length === 0) {
      message.warning('正在加载索引，请稍候...')
      await loadChaptersAndBuildIndex(loadIdRef.current)
      if (!invertedIndex) return
    }

    setLoading(true)
    setResults([])

    try {
      // 分词
      const queryWords = query
        .toLowerCase()
        .replace(/[^\w\u4e00-\u9fa5]/g, ' ')
        .split(/\s+/)
        .filter(w => w.length >= 1)

      if (queryWords.length === 0) {
        setLoading(false)
        return
      }

      // 找出包含查询词的文档
      const docScores = new Map<string, { score: number; matchedWords: Set<string> }>()

      for (const word of queryWords) {
        const docSet = invertedIndex.vocabulary.get(word)
        if (!docSet) continue

        // IDF 权重（简化版）
        const docFreq = docSet.size
        const idf = Math.log((invertedIndex.totalDocs + 1) / (docFreq + 1))

        for (const docPath of docSet) {
          const docLen = invertedIndex.docLengths.get(docPath) || 1
          const tf = 1 // 简化：每个词出现一次

          if (!docScores.has(docPath)) {
            docScores.set(docPath, { score: 0, matchedWords: new Set() })
          }
          const entry = docScores.get(docPath)!
          entry.score += (tf / docLen) * idf
          entry.matchedWords.add(word)
        }
      }

      // 过滤：AND 模式要求所有词都匹配
      let filteredDocs = Array.from(docScores.entries())

      if (queryMode === 'AND') {
        filteredDocs = filteredDocs.filter(([, entry]) =>
          queryWords.every(w => entry.matchedWords.has(w))
        )
      }

      // 章节范围过滤
      if (chapterRange.start || chapterRange.end) {
        filteredDocs = filteredDocs.filter(([path]) => {
          const ch = chapters.find(c => c.path === path)
          if (!ch) return true
          const match = ch.name.match(/第(\d+)章/)
          if (!match) return true
          const chNum = parseInt(match[1])
          if (chapterRange.start && chNum < chapterRange.start) return false
          if (chapterRange.end && chNum > chapterRange.end) return false
          return true
        })
      }

      // 排序并生成结果
      const searchResults: SearchResult[] = filteredDocs
        .sort((a, b) => b[1].score - a[1].score)
        .slice(0, 10)
        .map(([path, entry]) => {
          const ch = chapters.find(c => c.path === path)
          // 生成片段
          let snippet = ''
          if (ch) {
            const contentLower = ch.content.toLowerCase()
            const firstMatchIdx = Math.min(...queryWords.map(w => contentLower.indexOf(w)).filter(i => i >= 0))
            if (firstMatchIdx >= 0) {
              const start = Math.max(0, firstMatchIdx - 40)
              const end = Math.min(ch.content.length, firstMatchIdx + 100)
              snippet = (start > 0 ? '...' : '') + ch.content.slice(start, end) + (end < ch.content.length ? '...' : '')
            } else {
              snippet = ch.content.slice(0, 120) + '...'
            }
          }

          return {
            chapterPath: path,
            chapterName: ch?.name || path,
            score: entry.score,
            snippet,
            matchedWords: Array.from(entry.matchedWords),
          }
        })

      setResults(searchResults)

      if (searchResults.length === 0) {
        message.info('未找到匹配章节，尝试使用 OR 模式或放宽筛选条件')
      }
    } catch (error) {
      console.error('搜索失败:', error)
      message.error('搜索失败')
    } finally {
      setLoading(false)
    }
  }

  // 重建索引
  const handleRebuildIndex = async () => {
    setInvertedIndex(null)
    setResults([])
    await loadChaptersAndBuildIndex(loadIdRef.current)
    message.success('索引已重建')
  }

  // 高亮匹配的词
  const highlightMatches = (text: string, words: string[]): React.ReactNode => {
    if (!words.length) return text

    let result = text
    const parts: { text: string; highlight: boolean }[] = []

    // 简单高亮实现
    const lowerText = text.toLowerCase()
    const allMatches: { start: number; end: number }[] = []

    for (const word of words) {
      let idx = lowerText.indexOf(word.toLowerCase())
      while (idx >= 0) {
        allMatches.push({ start: idx, end: idx + word.length })
        idx = lowerText.indexOf(word.toLowerCase(), idx + 1)
      }
    }

    if (allMatches.length === 0) return text

    // 合并重叠区间并排序
    allMatches.sort((a, b) => a.start - b.start)
    const merged: { start: number; end: number }[] = []
    for (const m of allMatches) {
      if (merged.length === 0 || merged[merged.length - 1].end < m.start) {
        merged.push(m)
      } else {
        merged[merged.length - 1].end = Math.max(merged[merged.length - 1].end, m.end)
      }
    }

    let lastEnd = 0
    for (const m of merged) {
      if (m.start > lastEnd) {
        parts.push({ text: result.slice(lastEnd, m.start), highlight: false })
      }
      parts.push({ text: result.slice(m.start, m.end), highlight: true })
      lastEnd = m.end
    }
    if (lastEnd < result.length) {
      parts.push({ text: result.slice(lastEnd), highlight: false })
    }

    return (
      <>
        {parts.map((p, i) =>
          p.highlight ? (
            <mark key={i} style={{ background: '#ffe58f', padding: '0 2px' }}>{p.text}</mark>
          ) : (
            <span key={i}>{p.text}</span>
          )
        )}
      </>
    )
  }

  if (!projectRoot) {
    return (
      <div style={{ padding: 40, textAlign: 'center', color: '#999' }}>
        请先打开一个小说项目
      </div>
    )
  }

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 头部 */}
      <div style={{ padding: '12px 16px', borderBottom: '1px solid #e8e8e8' }}>
        <div style={{ marginBottom: 10 }}>
          <Space>
            <span style={{ fontSize: 13, fontWeight: 500 }}>🔍 相似章节检索</span>
            {indexStats && (
              <Tag color="green">
                索引: {indexStats.wordCount} 词 / {indexStats.chapterCount} 章
              </Tag>
            )}
          </Space>
        </div>

        {/* 索引状态 */}
        <div style={{ marginBottom: 10, fontSize: 12 }}>
          {indexLoading ? (
            <Tag icon={<Spin size="small" />}>正在构建索引...</Tag>
          ) : invertedIndex ? (
            <Tag color="green" icon={<CheckCircleOutlined />}>
              倒排索引已就绪
            </Tag>
          ) : (
            <Tag color="orange" icon={<WarningOutlined />}>
              索引未构建
            </Tag>
          )}
          <Button
            size="small"
            icon={<ReloadOutlined />}
            onClick={handleRebuildIndex}
            style={{ marginLeft: 8 }}
          >
            重建索引
          </Button>
        </div>

        {/* 搜索框 */}
        <Space direction="vertical" style={{ width: '100%' }}>
          <Input.Search
            placeholder="输入情节描述、角色名或关键词..."
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onSearch={performSearch}
            loading={loading}
            enterButton={
              <Button type="primary" icon={<SearchOutlined />}>
                搜索
              </Button>
            }
          />
        </Space>

        {/* 搜索选项 */}
        <div style={{ marginTop: 8 }}>
          <Button
            size="small"
            type="text"
            icon={<FilterOutlined />}
            onClick={() => setShowFilters(!showFilters)}
          >
            高级选项 {showFilters ? '▲' : '▼'}
          </Button>
          {showFilters && (
            <div style={{ marginTop: 8, padding: 8, background: '#f5f5f5', borderRadius: 6 }}>
              <Space direction="vertical" style={{ width: '100%' }}>
                <div>
                  <span style={{ fontSize: 11, marginRight: 8 }}>匹配模式：</span>
                  <Select
                    size="small"
                    value={queryMode}
                    onChange={setQueryMode}
                    options={[
                      { value: 'AND', label: 'AND（所有词都匹配）' },
                      { value: 'OR', label: 'OR（任一词匹配）' },
                    ]}
                    style={{ width: 160 }}
                  />
                </div>
                <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
                  <span style={{ fontSize: 11 }}>章节范围：</span>
                  <Input
                    size="small"
                    placeholder="起始章"
                    type="number"
                    min={1}
                    style={{ width: 70 }}
                    value={chapterRange.start || ''}
                    onChange={(e) => setChapterRange(prev => ({
                      ...prev,
                      start: e.target.value ? parseInt(e.target.value) : undefined
                    }))}
                  />
                  <span>-</span>
                  <Input
                    size="small"
                    placeholder="结束章"
                    type="number"
                    min={1}
                    style={{ width: 70 }}
                    value={chapterRange.end || ''}
                    onChange={(e) => setChapterRange(prev => ({
                      ...prev,
                      end: e.target.value ? parseInt(e.target.value) : undefined
                    }))}
                  />
                </div>
              </Space>
            </div>
          )}
        </div>

        <Alert
          message="使用倒排索引进行关键词检索，支持 AND/OR 查询和章节范围过滤"
          type="info"
          showIcon
          style={{ marginTop: 8, fontSize: 11 }}
        />
      </div>

      {/* 结果列表 */}
      <div style={{ flex: 1, overflow: 'auto', padding: 16 }}>
        {loading || indexLoading ? (
          <div style={{ textAlign: 'center', padding: 40 }}>
            <Spin tip={indexLoading ? '构建索引中...' : '搜索中...'} />
          </div>
        ) : results.length === 0 ? (
          <div style={{ color: '#999', textAlign: 'center', padding: 40, fontSize: 13 }}>
            {query ? '未找到相似章节' : '输入内容开始搜索'}
          </div>
        ) : (
          <List
            dataSource={results}
            renderItem={(item) => (
              <List.Item
                style={{ cursor: 'pointer' }}
                onClick={() => onJumpToChapter?.(item.chapterPath)}
              >
                <List.Item.Meta
                  title={
                    <Space>
                      <span>{item.chapterName}</span>
                      <Tag color="blue">
                        匹配度 {Math.round(item.score * 100)}%
                      </Tag>
                      {item.matchedWords.slice(0, 3).map(w => (
                        <Tag key={w} color="purple" style={{ fontSize: 10 }}>
                          {w}
                        </Tag>
                      ))}
                    </Space>
                  }
                  description={
                    <div
                      style={{
                        fontSize: 12,
                        color: '#666',
                        overflow: 'hidden',
                        textOverflow: 'ellipsis',
                        display: '-webkit-box',
                        WebkitLineClamp: 2,
                        WebkitBoxOrient: 'vertical',
                      }}
                    >
                      {highlightMatches(item.snippet, item.matchedWords)}
                    </div>
                  }
                />
              </List.Item>
            )}
          />
        )}
      </div>
    </div>
  )
}

export default VectorSearchPanel

/**
 * 章节分析面板
 * 提供：自动摘要、人物出场统计、对话分析、情节点提取
 */

import { useState } from 'react'
import {
  Button,
  Space,
  Card,
  message,
  Spin,
  Tabs,
  Statistic,
  Row,
  Col,
  Tag,
  List,
  Progress,
  Alert,
  Divider,
} from 'antd'
import {
  FileTextOutlined,
  TeamOutlined,
  MessageOutlined,
  ThunderboltOutlined,
  ReloadOutlined,
} from '@ant-design/icons'
import aiModelService from '../services/aiModels'

interface AnalysisPanelProps {
  chapterContent: string
  chapterPath: string | null
  projectRoot: string | null
}

interface CharacterAppearance {
  name: string
  count: number
  paragraphs: number
}

interface DialogueInfo {
  speaker: string
  content: string
  position: number
}

interface PlotPoint {
  order: number
  event: string
  description: string
}

const AnalysisPanel: React.FC<AnalysisPanelProps> = ({
  chapterContent,
  chapterPath,
  projectRoot,
}) => {
  const [analyzing, setAnalyzing] = useState(false)
  const [activeTab, setActiveTab] = useState<string>('summary')

  // 摘要
  const [summary, setSummary] = useState('')
  const [summaryLoading, setSummaryLoading] = useState(false)

  // 人物统计
  const [characters, setCharacters] = useState<CharacterAppearance[]>([])
  const [dialogues, setDialogues] = useState<DialogueInfo[]>([])
  const [dialogueRatio, setDialogueRatio] = useState(0)
  const [characterStatsLoading, setCharacterStatsLoading] = useState(false)

  // 情节点
  const [plotPoints, setPlotPoints] = useState<PlotPoint[]>([])
  const [plotPointsLoading, setPlotPointsLoading] = useState(false)

  // 生成自动摘要
  const handleGenerateSummary = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setSummaryLoading(true)
    try {
      const fullPrompt = `请为以下小说章节生成200字左右的摘要，概括核心情节、人物关系变化和关键事件：

${chapterContent.slice(0, 3000)}

摘要（200字左右）：` as string

      const result = await aiModelService.call('summary', fullPrompt, {
        systemPrompt: '你是一个小说摘要专家。请用简洁精炼的语言概括章节核心内容。',
      })

      if (result.success && result.content) {
        setSummary(result.content)
        setActiveTab('summary')
      } else {
        message.error(result.error || '摘要生成失败')
      }
    } catch (error) {
      message.error('摘要生成失败')
      console.error('摘要生成失败:', error)
    } finally {
      setSummaryLoading(false)
    }
  }

  // 人物出场统计
  const handleCharacterStats = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    if (!projectRoot) {
      message.warning('请先打开项目')
      return
    }
    setCharacterStatsLoading(true)
    try {
      // 读取角色列表
      let characterNames: string[] = []
      const charactersDir = `${projectRoot}/characters`
      const charsExistsResult = await window.electronAPI.exists(charactersDir)
      if (!charsExistsResult.success || !charsExistsResult.exists) {
        setCharacters([])
        setCharacterStatsLoading(false)
        return
      }
      const entriesResult = await window.electronAPI.readdir(charactersDir)
      if (!entriesResult.success) { console.error('读取characters目录失败:', entriesResult.error); setCharacters([]); setCharacterStatsLoading(false); return; }
      const entries = entriesResult.data || []
      const yamlFiles = entries.filter(
        (e: { name: string; isFile: boolean }) => e.isFile && e.name.endsWith('.yaml')
      )
      for (const file of yamlFiles) {
        const result = await window.electronAPI.yaml.read(`${charactersDir}/${file.name}`)
        if (result.success && result.data) {
          const data = result.data as Record<string, unknown>
          if (data.name && typeof data.name === 'string') {
            characterNames.push(data.name)
          }
        }
      }

      // 统计章节中出现的人物
      const content = chapterContent
      const charAppearances: Record<string, { count: number; paragraphs: Set<number> }> = {}

      // 按段落分割
      const paragraphs = content.split(/\n\n+/)

      paragraphs.forEach((para, paraIdx) => {
        for (const name of characterNames) {
          if (para.includes(name)) {
            if (!charAppearances[name]) {
              charAppearances[name] = { count: 0, paragraphs: new Set() }
            }
            charAppearances[name].count++
            charAppearances[name].paragraphs.add(paraIdx)
          }
        }
      })

      const sortedChars = Object.entries(charAppearances)
        .map(([name, stats]) => ({
          name,
          count: stats.count,
          paragraphs: stats.paragraphs.size,
        }))
        .sort((a, b) => b.count - a.count)

      setCharacters(sortedChars)

      // 提取对话
      const dialogueRegex = /[""''『』]([^""''『』]+)[""''『』]/g
      const extractedDialogues: DialogueInfo[] = []
      let match
      let pos = 0
      while ((match = dialogueRegex.exec(content)) !== null) {
        extractedDialogues.push({
          speaker: '',
          content: match[1],
          position: match.index,
        })
        pos++
        if (pos > 50) break
      }

      // 尝试识别说话者（简化版：找引号前的名字）
      const speakerRegex = /([A-Za-z\u4e00-\u9fa5]{2,4})[""'']/
      for (const d of extractedDialogues) {
        const beforeContent = content.slice(Math.max(0, d.position - 30), d.position)
        const speakerMatch = beforeContent.match(speakerRegex)
        if (speakerMatch) {
          d.speaker = speakerMatch[1]
        }
      }

      setDialogues(extractedDialogues.slice(0, 20))

      // 计算对话占比
      const totalChars = content.replace(/\s/g, '').length
      const dialogueChars = extractedDialogues.reduce((sum, d) => sum + d.content.length, 0)
      setDialogueRatio(totalChars > 0 ? (dialogueChars / totalChars) * 100 : 0)

      setActiveTab('characters')
    } catch (error) {
      message.error('统计分析失败')
    } finally {
      setCharacterStatsLoading(false)
    }
  }

  // 情节点提取
  const handlePlotPoints = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setPlotPointsLoading(true)
    try {
      const fullPrompt = `请分析以下小说章节，提取3-5个关键情节点，按时间顺序列出：

${chapterContent.slice(0, 3000)}

情节点列表（格式）：
1. [事件名称] - 简要描述
2. [事件名称] - 简要描述
...` as string

      const result = await aiModelService.call('summary', fullPrompt, {
        systemPrompt: '你是小说情节分析专家。请按时间顺序列出章节的关键事件。',
      })

      if (result.success && result.content) {
        // 解析情节点
        const lines = result.content.split('\n').filter(l => l.trim())
        const points: PlotPoint[] = []
        let order = 1
        for (const line of lines) {
          const match = line.match(/^\d+[.、]\s*(\[.+?\])?\s*(.+)/)
          if (match) {
            points.push({
              order: order++,
              event: match[1] || `情节点${order - 1}`,
              description: match[2].trim(),
            })
          }
        }
        if (points.length === 0) {
          points.push({ order: 1, event: '主要情节点', description: result.content })
        }
        setPlotPoints(points)
        setActiveTab('plotpoints')
      } else {
        message.error(result.error || '情节点提取失败')
      }
    } catch (error) {
      message.error('情节点提取失败')
    } finally {
      setPlotPointsLoading(false)
    }
  }

  // 快速分析（一次性生成所有）
  const handleFullAnalysis = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setAnalyzing(true)
    try {
      await handleGenerateSummary()
      await handleCharacterStats()
      await handlePlotPoints()
    } catch (error) {
      console.error('全量分析失败:', error)
    } finally {
      setAnalyzing(false)
    }
  }

  if (!chapterContent) {
    return (
      <div style={{ padding: 40, textAlign: 'center', color: '#999' }}>
        请先选择章节
      </div>
    )
  }

  const totalChars = chapterContent.replace(/\s/g, '').length
  const wordCount = chapterContent.length

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 头部 */}
      <div style={{ padding: '12px 16px', borderBottom: '1px solid #e8e8e8' }}>
        <div style={{ marginBottom: 10 }}>
          <span style={{ fontSize: 13, fontWeight: 500 }}>📊 章节分析</span>
        </div>

        {/* 基础统计 */}
        <Row gutter={8} style={{ marginBottom: 10 }}>
          <Col span={8}>
            <Statistic
              title={<span style={{ fontSize: 11 }}>字数</span>}
              value={wordCount}
              valueStyle={{ fontSize: 16 }}
            />
          </Col>
          <Col span={8}>
            <Statistic
              title={<span style={{ fontSize: 11 }}>字符</span>}
              value={totalChars}
              valueStyle={{ fontSize: 16 }}
            />
          </Col>
          <Col span={8}>
            <Statistic
              title={<span style={{ fontSize: 11 }}>对话占比</span>}
              value={dialogueRatio.toFixed(1)}
              suffix="%"
              valueStyle={{ fontSize: 16 }}
            />
          </Col>
        </Row>

        {/* 分析按钮 */}
        <Space wrap style={{ marginBottom: 8 }}>
          <Button
            size="small"
            icon={<FileTextOutlined />}
            onClick={handleGenerateSummary}
            loading={summaryLoading}
          >
            生成摘要
          </Button>
          <Button
            size="small"
            icon={<TeamOutlined />}
            onClick={handleCharacterStats}
            loading={characterStatsLoading}
          >
            人物统计
          </Button>
          <Button
            size="small"
            icon={<ThunderboltOutlined />}
            onClick={handlePlotPoints}
            loading={plotPointsLoading}
          >
            情节点
          </Button>
          <Button
            size="small"
            icon={<ReloadOutlined />}
            onClick={handleFullAnalysis}
            loading={analyzing}
          >
            全部分析
          </Button>
        </Space>
      </div>

      {/* 分析结果 */}
      <div style={{ flex: 1, overflow: 'auto', padding: 16 }}>
        <Tabs
          activeKey={activeTab}
          onChange={setActiveTab}
          size="small"
          items={[
            {
              key: 'summary',
              label: <span>📝 摘要</span>,
              children: (
                <div>
                  {summaryLoading ? (
                    <div style={{ textAlign: 'center', padding: 40 }}>
                      <Spin tip="生成摘要中..." />
                    </div>
                  ) : summary ? (
                    <Card size="small" style={{ whiteSpace: 'pre-wrap' }}>
                      {summary}
                    </Card>
                  ) : (
                    <Alert
                      message="点击「生成摘要」获取本章200字摘要"
                      type="info"
                      showIcon
                    />
                  )}
                </div>
              ),
            },
            {
              key: 'characters',
              label: <span>👥 人物</span>,
              children: (
                <div>
                  {characterStatsLoading ? (
                    <div style={{ textAlign: 'center', padding: 40 }}>
                      <Spin tip="分析人物中..." />
                    </div>
                  ) : (
                    <>
                      {/* 人物出场 */}
                      {characters.length > 0 ? (
                        <Card
                          size="small"
                          title="人物出场统计"
                          style={{ marginBottom: 12 }}
                        >
                          <List
                            size="small"
                            dataSource={characters.slice(0, 10)}
                            renderItem={(char) => (
                              <List.Item>
                                <div style={{ display: 'flex', justifyContent: 'space-between', width: '100%', alignItems: 'center' }}>
                                  <Tag color="blue">{char.name}</Tag>
                                  <Space size="small">
                                    <span style={{ fontSize: 11, color: '#999' }}>
                                      提及 {char.count} 次 · {char.paragraphs} 段
                                    </span>
                                    <Progress
                                      percent={Math.round((char.count / characters[0].count) * 100)}
                                      size="small"
                                      style={{ width: 60 }}
                                    />
                                  </Space>
                                </div>
                              </List.Item>
                            )}
                          />
                        </Card>
                      ) : (
                        <Alert
                          message="点击「人物统计」分析本章出场人物"
                          type="info"
                          showIcon
                        />
                      )}

                      {/* 对话分析 */}
                      {dialogues.length > 0 && (
                        <Card size="small" title="对话片段">
                          <List
                            size="small"
                            dataSource={dialogues.slice(0, 8)}
                            renderItem={(d) => (
                              <List.Item>
                                <div style={{ width: '100%' }}>
                                  {d.speaker && <Tag color="green" style={{ marginBottom: 4 }}>{d.speaker}</Tag>}
                                  <div style={{ fontSize: 12, fontStyle: 'italic', color: '#666' }}>
                                    「{d.content.slice(0, 60)}{d.content.length > 60 ? '...' : ''}」
                                  </div>
                                </div>
                              </List.Item>
                            )}
                          />
                          <Divider style={{ margin: '8px 0' }} />
                          <div style={{ fontSize: 11, color: '#999' }}>
                            共 {dialogues.length} 段对话，对话占比 {dialogueRatio.toFixed(1)}%
                          </div>
                        </Card>
                      )}
                    </>
                  )}
                </div>
              ),
            },
            {
              key: 'plotpoints',
              label: <span>⚡ 情节点</span>,
              children: (
                <div>
                  {plotPointsLoading ? (
                    <div style={{ textAlign: 'center', padding: 40 }}>
                      <Spin tip="提取情节点中..." />
                    </div>
                  ) : plotPoints.length > 0 ? (
                    <Card size="small" title="本章关键情节点">
                      <List
                        size="small"
                        dataSource={plotPoints}
                        renderItem={(point) => (
                          <List.Item>
                            <List.Item.Meta
                              avatar={<div style={{
                                width: 24,
                                height: 24,
                                borderRadius: '50%',
                                background: '#1890ff',
                                color: '#fff',
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center',
                                fontSize: 12,
                              }}>
                                {point.order}
                              </div>}
                              title={<span>{point.event}</span>}
                              description={<span style={{ fontSize: 12, color: '#666' }}>{point.description}</span>}
                            />
                          </List.Item>
                        )}
                      />
                    </Card>
                  ) : (
                    <Alert
                      message="点击「情节点」提取本章关键事件"
                      type="info"
                      showIcon
                    />
                  )}
                </div>
              ),
            },
          ]}
        />
      </div>
    </div>
  )
}

export default AnalysisPanel
